+import { resolve } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const searchPaths = options.searchPaths ?? [getCurrentDirectory()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const values: Record<string, unknown> = {};
+  let path: string | undefined;
+
+  for (const searchPath of searchPaths) {
+    const match = await findConfig(searchPath, options.name, formats);
+    if (!match) continue;
+
+    const content = await readTextFile(match);
+    const parsed = parseConfig(content, match, options);
+    const flattened = flattenConfig(parsed);
+
+    if (!path) path = match;
+    for (const [key, value] of Object.entries(flattened)) {
+      if (!(key in values)) values[key] = value;
+    }
+    if (!options.mergeConfigs) break;
+  }
+
+  return { path, values };
+}
+
+async function findConfig(
+  searchPath: string,
+  name: string,
+  formats: string[],
+): Promise<string | undefined> {
+  for (const format of formats) {
+    const fileName = format === ".rc" ? `.${name}rc` : `${name}${format}`;
+    const path = resolve(searchPath, fileName);
+    if (await fileExists(path)) return path;
+  }
+}
+
+function parseConfig(
+  content: string,
+  path: string,
+  options: ConfigOptions,
+): Record<string, unknown> {
+  try {
+    const value = options.parser
+      ? options.parser(content)
+      : path.endsWith(".json")
+      ? JSON.parse(content)
+      : parseRc(content);
+    if (!isPlainObject(value)) throw new TypeError("Configuration must be an object.");
+    return value;
+  } catch (error) {
+    if (error instanceof ConfigParseError) throw error;
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = line.indexOf("=");
+    if (index < 1) throw new TypeError(`Invalid RC line: ${line}`);
+    const key = line.slice(0, index).trim();
+    let value = line.slice(index + 1).trim();
+    if (!key) throw new TypeError(`Invalid RC line: ${line}`);
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new TypeError(`Unterminated quoted value for ${key}.`);
+      }
+      value = value.slice(1, -1);
+    }
+    values[key] = coerceRcValue(value);
+  }
+  return values;
+}
+
+function coerceRcValue(value: string): string | boolean | number {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (/^-?(?:\\d+\\.?\\d*|\\.\\d+)(?:[eE][+-]?\\d+)?$/.test(value)) {
+    return Number(value);
+  }
+  return value;
+}
+
+export function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+  result: Record<string, unknown> = {},
+): Record<string, unknown> {
+  for (const [rawKey, entry] of Object.entries(value)) {
+    const key = rawKey.split(".").map(kebabToCamelCase).join(".");
+    const fullKey = prefix ? `${prefix}.${key}` : key;
+    if (isPlainObject(entry)) flattenConfig(entry, fullKey, result);
+    else result[fullKey] = entry;
+  }
+  return result;
+}
+
+function kebabToCamelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, character: string) => character.toUpperCase());
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  if (!value || typeof value !== "object" || Array.isArray(value)) return false;
+  const prototype = Object.getPrototypeOf(value);
+  return prototype === Object.prototype || prototype === null;
+}
+
+function getCurrentDirectory(): string {
+  // dnt-shim-ignore
+  const { Deno, process } = globalThis as any;
+  if (Deno?.cwd) return Deno.cwd();
+  if (process?.cwd) return process.cwd();
+  return ".";
+}
+
+async function fileExists(path: string): Promise<boolean> {
+  try {
+    // dnt-shim-ignore
+    const { Deno } = globalThis as any;
+    if (Deno) {
+      const info = await Deno.stat(path);
+      return info.isFile;
+    }
+    const { stat } = await import("node:fs/promises");
+    return (await stat(path)).isFile();
+  } catch (error) {
+    if (error instanceof Error && (error.name === "NotFound" || (error as any).code === "ENOENT")) {
+      return false;
+    }
+    throw error;
+  }
+}
+
+async function readTextFile(path: string): Promise<string> {
+  // dnt-shim-ignore
+  const { Deno } = globalThis as any;
+  if (Deno) return await Deno.readTextFile(path);
+  const { readFile } = await import("node:fs/promises");
+  return await readFile(path, "utf8");
+}
